const data = $input.first().json.values || [];
const rows = data.slice(1);  // skip header

const candidates = rows
  .map((row, idx) => ({
    row_idx: idx + 2,
    keyword: (row[0] || '').trim(),
    estado: (row[1] || '').trim(),
    prioridad: (row[2] || '').trim(),
    url_post: (row[7] || '').trim(),
    posicion_gsc: parseFloat(row[9]) || 999
  }))
  .filter(r => r.estado === 'Publicado' && r.url_post && r.keyword)
  // Excluir títulos de posts importados (largos, con ':' o '|') — buscamos keywords naturales
  .filter(r => r.keyword.length <= 55 && !/[:|]|guía completa|todo lo que/i.test(r.keyword))
  .sort((a, b) => {
    // Priority Alta primero (curated por WF5), luego mejor posición GSC
    const pA = a.prioridad === 'Alta' ? 0 : (a.prioridad === 'Media' ? 1 : 2);
    const pB = b.prioridad === 'Alta' ? 0 : (b.prioridad === 'Media' ? 1 : 2);
    if (pA !== pB) return pA - pB;
    return a.posicion_gsc - b.posicion_gsc;
  })
  .slice(0, 20);

if (candidates.length === 0) {
  throw new Error('AEO Monitor: 0 keywords candidatas. Verifica que haya filas con estado="Publicado" + url_post en hoja Blog.');
}

return candidates.map(c => ({ json: c }));

const keyword = $('Pick Top 20 Keywords').item.json.keyword || '';
const url_post = $('Pick Top 20 Keywords').item.json.url_post || '';
const firstResp = $('SerpAPI Query').item.json;
const secondResp = $input.item.json;

function emit(extra) {
  return { json: Object.assign({ keyword, url_post, bf_citado: false, bf_position: 0, bf_url: '', bf_snippet: '', competitors_top3: '', ai_overview_excerpt: '', no_ai_overview: false }, extra) };
}

// Si la primera respuesta no trae ai_overview, no hubo AIO para esta query
if (!firstResp || (!firstResp.ai_overview && !firstResp.error)) {
  return emit({ ai_overview_excerpt: '(sin AI Overview en SERP)', no_ai_overview: true });
}
if (firstResp.error || firstResp.errorMessage) {
  return emit({ ai_overview_excerpt: '[ERROR SerpAPI 1st] ' + (firstResp.error?.message || firstResp.errorMessage || 'unknown'), no_ai_overview: true });
}

// Determinar de dónde sacar el contenido real del AI Overview
let aio = null;
if (firstResp.ai_overview && (firstResp.ai_overview.references || firstResp.ai_overview.text_blocks)) {
  aio = firstResp.ai_overview; // sync case (raro)
} else if (secondResp && !secondResp.error && secondResp.ai_overview && (secondResp.ai_overview.references || secondResp.ai_overview.text_blocks)) {
  aio = secondResp.ai_overview; // async wrapped
} else if (secondResp && !secondResp.error && (secondResp.references || secondResp.text_blocks)) {
  aio = secondResp; // async root
}

// Caso especial: SerpAPI dice 'Fully empty' — Google no generó AIO real
const aioState = secondResp?.search_information?.ai_overview_state;
if (aioState === 'Fully empty' || (secondResp?.error && /hasn't returned any results/i.test(secondResp.error))) {
  return emit({ ai_overview_excerpt: '(AIO state: Fully empty — Google no generó contenido para esta query)', no_ai_overview: true });
}

if (!aio) {
  return emit({ ai_overview_excerpt: '(AI Overview async no disponible en 2do call)', no_ai_overview: true });
}

const refs = Array.isArray(aio.references) ? aio.references : [];
const textBlocks = Array.isArray(aio.text_blocks) ? aio.text_blocks : [];

// Extract excerpt del AI Overview
const fullText = textBlocks.map(b => b.snippet || b.text || '').filter(Boolean).join(' ').trim();
const excerpt = fullText.substring(0, 250);

// Detect bigotescaninos.com en references
let bfRef = null;
let bfPos = 0;
for (let i = 0; i < refs.length; i++) {
  const link = refs[i].link || '';
  if (link.toLowerCase().includes('bigotescaninos.com')) {
    bfRef = refs[i];
    bfPos = i + 1;
    break;
  }
}

// Top 3 competitors (sources or domains)
const top3 = refs.slice(0, 3)
  .map(r => r.source || (r.link || '').replace(/^https?:\/\/(www\.)?/, '').split('/')[0] || r.title || '')
  .filter(Boolean)
  .slice(0, 3)
  .join(' | ');

return emit({
  bf_citado: !!bfRef,
  bf_position: bfPos,
  bf_url: bfRef ? bfRef.link : '',
  bf_snippet: bfRef ? String(bfRef.snippet || '').substring(0, 200) : '',
  competitors_top3: top3,
  ai_overview_excerpt: excerpt,
  no_ai_overview: false
});

const items = $input.all().map(it => it.json);
const total = items.length;

// Heurística de país: keyword contiene modificador colombiano
function isColombian(kw) {
  const k = (kw || '').toLowerCase();
  return /\b(colombia|bogot[áa]|medell[íi]n|cali|barranquilla|cartagena|pesos colombianos)\b|\bcop\b/.test(k);
}

const cited = items.filter(i => i.bf_citado);
const noAIO = items.filter(i => i.no_ai_overview).length;
const withAIO = total - noAIO;

// Split por país (solo de queries con AIO real)
const itemsAIO = items.filter(i => !i.no_ai_overview);
const itemsAIO_CO = itemsAIO.filter(i => isColombian(i.keyword));
const itemsAIO_Gen = itemsAIO.filter(i => !isColombian(i.keyword));
const cited_CO = cited.filter(i => isColombian(i.keyword)).length;
const cited_Gen = cited.filter(i => !isColombian(i.keyword)).length;

// Top 3 dominios competidores (across queries con AIO)
const competitorCounts = {};
itemsAIO.forEach(i => {
  const top3 = (i.competitors_top3 || '').split(' | ').filter(Boolean);
  top3.forEach(c => {
    const key = c.trim().replace(/^www\./, '');
    if (key) competitorCounts[key] = (competitorCounts[key] || 0) + 1;
  });
});
const topCompetitors = Object.entries(competitorCounts).sort((a,b) => b[1]-a[1]).slice(0,3);

// Fecha Colombia
const now = new Date();
const colombiaOffset = -5 * 60;
const colombiaTime = new Date(now.getTime() + (colombiaOffset - now.getTimezoneOffset()) * 60000);
const today = colombiaTime.toISOString().split('T')[0];

// Build sheet append payload
const values = items.map(i => [
  today,
  i.keyword,
  i.bf_citado ? 'SI' : 'NO',
  i.bf_position || '',
  i.bf_url || '',
  i.bf_snippet || '',
  i.competitors_top3 || '',
  (i.ai_overview_excerpt || '').substring(0, 500)
]);
const sheet_payload = JSON.stringify({ values });

// Telegram message
const lines = [];
lines.push('\u{1F4CA} *AEO Monitor — Reporte semanal*');
lines.push('');
lines.push('\u{1F3AF} Bigotes Caninos citado: *' + cited.length + '/' + withAIO + '*');
lines.push('  \u{1F1E8}\u{1F1F4} Colombianas: ' + cited_CO + '/' + itemsAIO_CO.length);
lines.push('  \u{1F30E} Generales: ' + cited_Gen + '/' + itemsAIO_Gen.length);
lines.push('\u{1F4ED} Sin AI Overview: ' + noAIO + ' keywords');
lines.push('\u{1F4DD} Total monitoreado: ' + total);

if (topCompetitors.length > 0) {
  lines.push('');
  lines.push('\u{1F947} *Top dominios en tu nicho:*');
  topCompetitors.forEach(([dom, count]) => {
    lines.push('  • ' + dom + ' (' + count + ')');
  });
}

if (cited.length > 0) {
  lines.push('');
  lines.push('✅ *Citaciones detectadas:*');
  cited.forEach(c => {
    const flag = isColombian(c.keyword) ? '\u{1F1E8}\u{1F1F4} ' : '';
    lines.push('  • ' + flag + c.keyword + ' (pos ' + c.bf_position + ')');
  });
} else {
  lines.push('');
  lines.push('Aún sin citaciones esta semana — la autoridad crece con el tiempo \u{1F408}‍⬛');
}

// Insight contextual de la semana
lines.push('');
if (cited_CO >= 3) {
  lines.push('\u{1F4A1} *Tip:* Tienes 3+ citas colombianas — momento de bajar cuota WF5 a ~27% (4 de 15 ideas)');
} else if (cited.length === 0 && topCompetitors.some(([d]) => /youtube|tiktok|instagram/i.test(d))) {
  lines.push('\u{1F4A1} *Insight:* Plataformas de video dominan tu nicho. AEO en español favorece contenido visual.');
} else if (cited.length === 0) {
  lines.push('\u{1F4A1} *Tip:* Compites con blogs SEO establecidos. Tu ventaja: voz cercana + contexto colombiano que ellos no tienen.');
} else {
  lines.push('\u{1F389} *¡Primera cita detectada!* El stack AEO empieza a funcionar. Mantén el ritmo de publicación.');
}

const summary = lines.join('\n');

return [{
  json: {
    sheet_payload,
    cited_count: cited.length,
    total_count: total,
    with_aio_count: withAIO,
    no_aio_count: noAIO,
    summary
  }
}];
